function DocEditor({ doc, collaborators, onUpdate }) {
  const { div, article, section } = tags;
  const [showToolbar, setShowToolbar] = createSignal(false);
  const [toolbarPos, setToolbarPos] = createSignal({ x: 0, y: 0 });
  const [showSlash, setShowSlash] = createSignal(false);
  const [showMention, setShowMention] = createSignal(false);

  const handleSelection = () => {
    const sel = window.getSelection();
    if (sel && !sel.isCollapsed) {
      const rect = sel.getRangeAt(0).getBoundingClientRect();
      setToolbarPos({ x: rect.left + rect.width / 2, y: rect.top - 8 });
      setShowToolbar(true);
    } else {
      setShowToolbar(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === '/' && e.target.textContent === '') {
      setShowSlash(true);
    } else if (e.key === '@') {
      setShowMention(true);
    } else if (e.key === 'Escape') {
      setShowSlash(false);
      setShowMention(false);
    }
  };

  return div({ class: css('_flex _col _hfull _relative paper-prose') },
    // Remote cursors layer
    div({ class: css('_absolute _inset0 _pointer[none] _z[10]') },
      ...collaborators.filter(c => c.cursor).map(c =>
        RemoteCursor({ user: c, position: c.cursor })
      )
    ),
    // Remote selections layer
    div({ class: css('_absolute _inset0 _pointer[none] _z[5]') },
      ...collaborators.filter(c => c.selection).map(c =>
        div({ 
          class: css('paper-selection'),
          style: `background: ${c.color}20; position: absolute; top: ${c.selection.top}px; left: ${c.selection.left}px; width: ${c.selection.width}px; height: ${c.selection.height}px;`
        })
      )
    ),
    // Floating toolbar
    showToolbar() ? BlockToolbar({
      position: toolbarPos(),
      onFormat: (cmd) => document.execCommand(cmd),
      onClose: () => setShowToolbar(false)
    }) : null,
    // Editor content
    article({
      class: css('_flex1 _outline[none] _mw[680px] _mx[auto] _py8 _px4'),
      contenteditable: 'true',
      onmouseup: handleSelection,
      onkeyup: handleSelection,
      onkeydown: handleKeyDown,
      oninput: (e) => onUpdate(e.target.innerHTML)
    },
      ...doc.blocks.map(block => renderBlock(block))
    ),
    // Slash command menu
    showSlash() ? SlashCommand({
      onSelect: (type) => { insertBlock(type); setShowSlash(false); },
      onClose: () => setShowSlash(false)
    }) : null,
    // Mention popup
    showMention() ? MentionPopup({
      collaborators,
      onSelect: (user) => { insertMention(user); setShowMention(false); },
      onClose: () => setShowMention(false)
    }) : null
  );
}

function renderBlock(block) {
  const { div, p, h1, h2, h3, ul, ol, li, blockquote, pre, code, img } = tags;
  switch (block.type) {
    case 'paragraph': return p({ 'data-block-id': block.id }, block.content);
    case 'heading1': return h1({ 'data-block-id': block.id }, block.content);
    case 'heading2': return h2({ 'data-block-id': block.id }, block.content);
    case 'heading3': return h3({ 'data-block-id': block.id }, block.content);
    case 'bullet-list': return ul({ 'data-block-id': block.id }, ...block.items.map(i => li({}, i)));
    case 'numbered-list': return ol({ 'data-block-id': block.id }, ...block.items.map(i => li({}, i)));
    case 'quote': return blockquote({ 'data-block-id': block.id, class: css('_borderL4 _border[var(--primary)] _pl4 _italic') }, block.content);
    case 'code': return pre({ 'data-block-id': block.id, class: css('_p4 _r2 _bg[var(--surface-raised)]') }, code({}, block.content));
    case 'image': return img({ 'data-block-id': block.id, src: block.src, alt: block.alt, class: css('_wfull _r2') });
    default: return p({ 'data-block-id': block.id }, block.content);
  }
}

function MinimalEditor({ doc, onUpdate }) {
  const { div, article, span } = tags;
  const [wordCount, setWordCount] = createSignal(0);

  const countWords = (text) => text.trim().split(/\s+/).filter(w => w).length;

  return div({ class: css('_flex _col _hfull _relative') },
    article({
      class: css('_flex1 _outline[none] _mw[600px] _mx[auto] _py12 _px4 paper-prose'),
      contenteditable: 'true',
      oninput: (e) => {
        onUpdate(e.target.innerHTML);
        setWordCount(countWords(e.target.textContent));
      }
    }),
    span({ class: css('_absolute _bottom4 _right4 _textsm _fgmuted') },
      () => `${wordCount()} words`
    )
  );
}

function PresentationView({ doc }) {
  const { article } = tags;
  return article({ class: css('_mw[680px] _mx[auto] _py8 _px4 paper-prose') },
    ...doc.blocks.map(block => renderBlock(block))
  );
}

